  const ties=arr.filter(d=>d.totalScore===mx);
  return ties.sort((a,b)=>{
    const tb=(b.arcScore||0)+(b.progScore||0)+(b.srScore||0);
    const ta=(a.arcScore||0)+(a.progScore||0)+(a.srScore||0);
    if(tb!==ta)return tb-ta;
