function T(key, p){
  const dict = isEN ? STR.en : STR.fr;
  let s = dict[key];
  if (s === undefined) s = STR.fr[key] !== undefined ? STR.fr[key] : key;
  if (typeof s !== 'string') return s;
  if (!p) return s;
  return s.replace(/\{(\w+)\}/g, function(_, n){ return (p[n]!==undefined && p[n]!==null) ? String(p[n]) : ''; });
}
function TConfLabel(label){
  const dict = isEN ? STR.en.confLabels : STR.fr.confLabels;
  return dict[label] || label;
}
