let confLabelGlobal='Inconnue', confColor='#888', confSigneTxt='', confHeureTxt='', confEcartS=null, confEcartH=null, confSigneLabel='Inconnue', confHeureLabel='Inconnue';
try{
  const sortedSig=ascPeaksSorted.map(e=>e[1].totalScore);
  let ecartSrel=null;
  if(sortedSig.length>=2&&sortedSig[0]>0){
    confEcartS=sortedSig[0]-sortedSig[1];
    ecartSrel=confEcartS/sortedSig[0];
    // [v5.8 P1.3] Seuils durcis suite au benchmark celebs (0/6 top-1 ASC correct sur l'ancien
    // calibrage qui labellisait "Moyenne" des prédictions à 9-15% d'écart pourtant fausses).
    // Nouveau : on demande un écart ABSOLU plus large + cohérence multi-techniques pour autoriser
    // les labels >= Moyenne. Sinon plafond "Faible" (annonce honnête de l'incertitude).
    if(ecartSrel>=0.20)confSigneLabel='Forte';
    else if(ecartSrel>=0.10)confSigneLabel='Moyenne';
    else if(ecartSrel>=0.04)confSigneLabel='Faible';
    else confSigneLabel='Très faible';
    const cc=Number(best?.coherenceCount)||0;
    if(cc<2&&(confSigneLabel==='Forte'||confSigneLabel==='Moyenne')){
      confSigneLabel='Faible';
    }
    // [v5.10 Fix B] Degrader la confiance signe en cas de desaccord fort entre le Top-1
    // questionnaire et le signe predit. Cas YSL v5.9.1 : best=Scorpion, qTopSign=Verseau
    // (conv Q 1.47x sur 22 vs 15) -> label initial "Moyenne" mais signe FAUX, l'utilisateur
    // recevait un faux signal de fiabilite. Si qTopSign existe ET difere de best.ascSign
    // normalise ET qConvergence >= 0.30 (Q vraiment convergent), on degrade d'un cran.
    // Effet collateral utile : "Moyenne" -> "Faible" declenche Fix B v5.9.1 (4 alts au lieu
    // de 2) et top-3 Q forces -> Verseau remonte plus visible. Cas deja Faible/Tres faible
    // non affectes (plancher). Cas best == qTopSign non affectes (Beauvoir, Gainsbourg,
    // Deneuve, Proust dans le bench actuel).
    if(qTopSign && qConvergence>=0.30){
      const bestSignNorm=normSignName(best?.wSign||best?.ascSign||'');
      if(bestSignNorm && bestSignNorm!==qTopSign){
        if(confSigneLabel==='Forte')confSigneLabel='Moyenne';
        else if(confSigneLabel==='Moyenne')confSigneLabel='Faible';
      }
    }
  }
  const bestSignKey=best.wSign||best.ascSign||'?';
  const sameSignSlots=validDetail.filter(d=>((d.wSign||d.ascSign||'?')===bestSignKey)).sort((a,b)=>b.totalScore-a.totalScore);
  let ecartHrel=null;
  if(sameSignSlots.length>=2&&sameSignSlots[0].totalScore>0){
    confEcartH=sameSignSlots[0].totalScore-sameSignSlots[1].totalScore;
    ecartHrel=confEcartH/sameSignSlots[0].totalScore;
    // [v5.8 P1.3] Seuils heure également durcis : un "Forte" à 5% c'était trompeur, vu qu'on
    // se trompait souvent quand même sur le SIGNE — l'heure exacte importe peu si le signe est faux.
    if(ecartHrel>=0.08)confHeureLabel='Forte';
    else if(ecartHrel>=0.03)confHeureLabel='Moyenne';
    else if(ecartHrel>=0.01)confHeureLabel='Faible';
    else confHeureLabel='Très faible';
  }
  const confRank={'Forte':3,'Moyenne':2,'Faible':1,'Très faible':0,'Inconnue':-1};
  const rS=confRank[confSigneLabel]??-1, rH=confRank[confHeureLabel]??-1;
  const minR=Math.min(rS,rH);
  confLabelGlobal=Object.keys(confRank).find(k=>confRank[k]===minR)||'Inconnue';
  confColor=minR>=3?'#1d8a3a':minR===2?'#b8860b':minR===1?'#d97706':'#c0392b';
  const sGap = confEcartS!=null ? T('confSignGap',{x:sf(confEcartS),y:(ecartSrel*100).toFixed(1)}) : '';
  const hGap = confEcartH!=null ? T('confTimeGap',{x:sf(confEcartH),y:(ecartHrel*100).toFixed(2)}) : '';
  confSigneTxt = T('confSign',{sign:best.ascSign||'?',label:TConfLabel(confSigneLabel),gap:sGap});
  confHeureTxt = T('confTime',{time:best.time||'?',label:TConfLabel(confHeureLabel),gap:hGap});
}catch(eConf){}

