  let g=280.46061837+360.98564736629*(J-2451545)+0.000387933*T*T;g=((g%360)+360)%360;
  const lst=((g+ut*1.00273790935*15+lon)%360+360)%360;
  const eps=(23.4393-0.013*T)*R;const A=lst*R;const L=lat*R;
  return((Math.atan2(-Math.cos(A),Math.sin(A)*Math.cos(eps)+Math.tan(L)*Math.sin(eps))/R+180)%360+360)%360;
}
