function clockToMin(tok){
  if(tok==null||tok==='')return null;
  let t=String(tok).trim().replace(/h/gi,':').replace(/\s/g,'');
  const mm=t.match(/^(\d{1,2})(?::(\d{2}))?$/);
  if(!mm)return null;
  let hh=parseInt(mm[1],10),m=mm[2]?parseInt(mm[2],10):0;
  if(m>59||hh>24||hh<0)return null;
  if(hh===24)return m===0?1440:null;
  return hh*60+m;
}
function buildPlage(v){
  const raw=(v.plage_naissance||v.plageNaissance||'').toString().trim();
  function tightStr(s){
    return String(s||'').replace(/[\s\u00A0\u202F\uFEFF]/g,'').replace(/h/gi,':').replace(/[\u2013\u2014\u2212]/g,'-');
  }
  const tightRaw=tightStr(raw);
  if(/^0+:0+-24(:0+)?$/i.test(tightRaw)||/^0+:0+-23:59$/i.test(tightRaw))return null;
  let lo,hi,label='';
  if(raw){
    const g=raw.match(/(\d{1,2}(?::\d{2})?)\s*[-\u2013\u2014\u2212]\s*(\d{1,2}(?::\d{2})?)/i);
    if(g){lo=clockToMin(g[1]);hi=clockToMin(g[2]);label=raw;}
  }
  if((lo==null||hi==null)&&v.heure_naissance_min){
    lo=clockToMin(v.heure_naissance_min);
    hi=clockToMin(v.heure_naissance_max);
    label=String(v.heure_naissance_min||'')+' — '+String(v.heure_naissance_max||'');
    const tightLbl=tightStr(label);
    if(/^0+:0+-24(:0+)?$/i.test(tightLbl)||/^0+:0+-23:59$/i.test(tightLbl))return null;
  }
  if(lo==null||hi==null)return null;
  if(lo>hi){const t=lo;lo=hi;hi=t;}
  if(hi>=1440)hi=1439;
  if(lo>1439)return null;
  if(lo<=0&&hi>=1439)return null;
  return{lo,hiInc:hi,label:label||'plage'};
}
function fenOverlapsPlage(s,e,pl){
  if(!pl)return true;
  const last=e-1;
  if(last<s)return false;
  return Math.max(s,pl.lo)<=Math.min(last,pl.hiInc);
}
